import type {
  EnumSchema,
  GeneratedSchema,
  GeneratedSchemas,
  ObjectSchema,
  PropertyType,
  Schema,
} from '@causa/workspace-core';
import { pascalCase } from 'change-case';
import { mkdir, writeFile } from 'fs/promises';
import { dirname, relative } from 'path';
import prettier from 'prettier';

/**
 * The leading comment for any TypeScript source file emitted by the code generators.
 */
export const LEADING_COMMENT =
  'This file was generated by the Causa command line. Do not edit it manually.';

/**
 * The default suffix used to identify constraint classes (e.g. `FooConstraint`).
 */
export const DEFAULT_CONSTRAINT_SUFFIX = 'Constraint';

/**
 * Returns the given property name as it should appear in a TypeScript object literal or class field: bare when it is a
 * valid identifier, JSON-stringified otherwise.
 */
export function propertyKey(name: string): string {
  return /^[A-Za-z_$][A-Za-z0-9_$]*$/.test(name) ? name : JSON.stringify(name);
}

/**
 * Strips `suffix` from `name`. Throws when `name` does not end with `suffix`.
 */
export function stripConstraintSuffix(name: string, suffix: string): string {
  if (!name.endsWith(suffix)) {
    throw new Error(`Constraint name '${name}' does not end with '${suffix}'.`);
  }
  return name.slice(0, -suffix.length);
}

/**
 * Returns the path of the schema constrained by `schema` (via `extensions.constraintFor`), or `undefined` when
 * `schema` is not an object schema or carries no `constraintFor` extension.
 */
export function getConstraintBasePath(schema: Schema): string | undefined {
  if (schema.kind !== 'object') {
    return undefined;
  }
  const value = schema.extensions.constraintFor;
  return typeof value === 'string' ? value : undefined;
}

/**
 * Returns the object schema constrained by `schema` (via `extensions.constraintFor`), or `undefined` when `schema` is
 * not a constraint, when the reference is missing from `schemas`, or when the target is not an object schema.
 */
export function getConstraintBaseObject(
  schema: Schema,
  schemas: Record<string, Schema>,
): ObjectSchema | undefined {
  const path = getConstraintBasePath(schema);
  if (path === undefined) {
    return undefined;
  }
  const base = schemas[path];
  return base?.kind === 'object' ? base : undefined;
}

/**
 * Returns the {@link EnumSchema} referenced by a property named `propertyName` on `schema` or on its `constraintFor`
 * base object, or `undefined` when neither has a ref-to-enum property of that name.
 *
 * Used to recover the enum case behind a const-valued constraint property, so generated code can reference the enum
 * member by name rather than emitting the raw value.
 */
export function resolveEnumForObjectProperty(
  schema: ObjectSchema,
  propertyName: string,
  schemas: Record<string, Schema>,
): EnumSchema | undefined {
  for (const obj of [schema, getConstraintBaseObject(schema, schemas)]) {
    const property = obj?.properties.find((p) => p.name === propertyName);
    if (property?.type.kind === 'ref') {
      const target = schemas[property.type.ref];
      if (target?.kind === 'enum') {
        return target;
      }
    }
  }

  return undefined;
}

/**
 * Returns the {@link GeneratedSchema} entry for the given schema path; throws when missing.
 */
export function findModelClass(
  modelClassSchemas: GeneratedSchemas,
  path: string,
): GeneratedSchema {
  const entry = modelClassSchemas[path];
  if (!entry) {
    throw new Error(
      `Schema '${path}' is not present in the model-class generator output.`,
    );
  }
  return entry;
}

/**
 * Returns deduplicated, valid TypeScript enum case names for the given enum schema (preserving source order).
 */
export function enumCaseNames(schema: EnumSchema): string[] {
  const seen = new Map<string, number>();
  return schema.values.map((value) => {
    const base = pascalCase(
      typeof value === 'string' ? value : `const_${value}`,
    );
    const safe = /^[A-Za-z_$]/.test(base) ? base : `_${base}`;
    const count = seen.get(safe) ?? 0;
    seen.set(safe, count + 1);
    return count === 0 ? safe : `${safe}_${count + 1}`;
  });
}

/**
 * Returns the TypeScript enum case name corresponding to the given raw value, or `undefined` when the value is absent
 * from the enum.
 */
export function findEnumCaseName(
  schema: EnumSchema,
  value: unknown,
): string | undefined {
  const index = (schema.values as unknown[]).indexOf(value);
  if (index < 0) {
    return undefined;
  }
  return enumCaseNames(schema)[index];
}

/**
 * Recursively collects the schema paths referenced by the given property type into `out`.
 *
 * @param type Type to walk.
 * @param out Set to accumulate refs into.
 * @param accept Optional predicate; refs for which it returns `false` are skipped (but the walk continues into nested
 *   types). Defaults to accepting every ref.
 */
export function collectRefs(
  type: PropertyType,
  out: Set<string>,
  accept: (ref: string) => boolean = () => true,
): void {
  switch (type.kind) {
    case 'ref':
      if (accept(type.ref)) {
        out.add(type.ref);
      }
      return;
    case 'array':
      collectRefs(type.items, out, accept);
      return;
    case 'map':
      if (type.items !== 'any') {
        collectRefs(type.items, out, accept);
      }
      return;
    default:
      return;
  }
}

/**
 * Kahn-style topological sort with deterministic tiebreak (alphabetical by `nameOf`, then by node id).
 *
 * @param nodes The nodes (schema paths) to sort.
 * @param dependenciesOf Returns the nodes that must be emitted before `node`. Dependencies outside `nodes` are ignored.
 * @param nameOf Returns the display name used for the alphabetical tiebreak.
 * @returns The nodes in dependency-respecting order.
 * @throws When the dependency graph contains a cycle.
 */
export function topologicalSort(
  nodes: string[],
  dependenciesOf: (node: string) => Iterable<string>,
  nameOf: (node: string) => string,
): string[] {
  const nodeSet = new Set(nodes);
  const inDegree = new Map<string, number>();
  const dependents = new Map<string, string[]>();
  for (const node of nodes) {
    inDegree.set(node, 0);
    dependents.set(node, []);
  }

  for (const node of nodes) {
    for (const dep of dependenciesOf(node)) {
      if (!nodeSet.has(dep) || dep === node) {
        continue;
      }
      inDegree.set(node, (inDegree.get(node) ?? 0) + 1);
      dependents.get(dep)?.push(node);
    }
  }

  const ready = nodes.filter((n) => (inDegree.get(n) ?? 0) === 0);
  const result: string[] = [];
  while (ready.length > 0) {
    ready.sort(
      (a, b) => nameOf(a).localeCompare(nameOf(b)) || a.localeCompare(b),
    );
    const next = ready.shift()!;
    result.push(next);
    for (const dependent of dependents.get(next) ?? []) {
      const remaining = (inDegree.get(dependent) ?? 0) - 1;
      inDegree.set(dependent, remaining);
      if (remaining === 0) {
        ready.push(dependent);
      }
    }
  }

  if (result.length !== nodes.length) {
    throw new Error('Cycle detected in schema dependency graph.');
  }
  return result;
}

/**
 * Merges the given symbol additions into `target` in place. Keys are module specifiers or absolute file paths.
 */
export function mergeImports(
  target: Record<string, Set<string>>,
  additions: Record<string, string[]>,
): void {
  for (const [path, symbols] of Object.entries(additions)) {
    const existing = target[path];
    if (existing) {
      for (const s of symbols) {
        existing.add(s);
      }
    } else {
      target[path] = new Set(symbols);
    }
  }
}

/**
 * Renders the source for an imports dictionary, sorted: module specifiers first (alphabetically), then absolute paths
 * converted to relative `./...js` imports. Type-only imports are deduplicated when their value-import counterpart is
 * also present.
 *
 * @param imports Imports dictionary.
 * @param outputPath Absolute path of the file the imports are being emitted into (used to compute relative paths).
 */
export function renderImports(
  imports: Record<string, Set<string>>,
  outputPath: string,
): string {
  const entries = Object.entries(imports);
  if (entries.length === 0) {
    return '';
  }

  const outputDir = dirname(outputPath);
  const sorted = entries
    .map(([path, symbols]) => {
      let specifier = path;
      if (path.startsWith('/')) {
        specifier = relative(outputDir, path);
        if (!specifier.startsWith('.')) {
          specifier = `./${specifier}`;
        }
        specifier = specifier.replace(/\.ts$/, '.js');
      }
      return { path, symbols, specifier };
    })
    .toSorted(
      (a, b) =>
        Number(a.path.startsWith('/')) - Number(b.path.startsWith('/')) ||
        a.specifier.localeCompare(b.specifier),
    );

  const lines: string[] = [];
  for (const { specifier, symbols } of sorted) {
    if (symbols.size === 0) {
      lines.push(`import '${specifier}';`);
      continue;
    }
    const symbolsList = [...symbols]
      .filter((s) => !s.startsWith('type ') || !symbols.has(s.slice(5)))
      .toSorted()
      .join(', ');
    lines.push(`import { ${symbolsList} } from '${specifier}';`);
  }
  return lines.join('\n');
}

/**
 * Formats the given source with `prettier` and writes it to `outputPath`, creating the parent directory if needed.
 */
export async function formatAndWriteTypeScript(
  outputPath: string,
  source: string,
): Promise<void> {
  const prettierConfig = await prettier.resolveConfig(outputPath);
  const formatted = await prettier.format(source, {
    parser: 'typescript',
    ...prettierConfig,
  });
  await mkdir(dirname(outputPath), { recursive: true });
  await writeFile(outputPath, formatted);
}

/**
 * Base class for TypeScript code generators. Owns:
 * - the imports dictionary and its rendering,
 * - the leading comment + prettier formatting + file writing.
 *
 * Subclasses build the body string and call {@link renderFile} to finish.
 */
export abstract class BaseTypeScriptCodeGenerator {
  /**
   * Schemas successfully emitted, indexed by their source path. Populated by subclasses as they emit each schema.
   */
  readonly generatedSchemas: GeneratedSchemas = {};

  /**
   * Imports collected while emitting. Keys are module specifiers or absolute file paths; values are the symbols to
   * import.
   */
  private readonly imports: Record<string, Set<string>> = {};

  /**
   * @param outputPath Absolute path of the file the rendered source will be written to.
   */
  protected constructor(readonly outputPath: string) {}

  /**
   * Merges the given imports into the generator's imports dictionary.
   */
  protected addImports(imports: Record<string, string[]>): void {
    mergeImports(this.imports, imports);
  }

  /**
   * Renders the collected imports as a source block (see {@link renderImports}).
   */
  protected emitImports(): string {
    return renderImports(this.imports, this.outputPath);
  }

  /**
   * Prepends the leading comment + imports to the given body, formats the result with `prettier`, and writes it to
   * {@link outputPath}.
   */
  protected async renderFile(body: string): Promise<void> {
    const source = [
      ...LEADING_COMMENT.split('\n').map((l) => `// ${l}`),
      '',
      this.emitImports(),
      '',
      body,
    ].join('\n');
    await formatAndWriteTypeScript(this.outputPath, source);
  }
}
